module top_module(clk, hardreset, reset);input clk, hardreset; 
 output reset; 
 reg [3:0] unused_reset_reg, next_reset_reg; 
 assign reset = unused_reset_reg[3]; 
 initial unused_reset_reg = 4'hF; 
 always @ (posedge clk or posedge hardreset) 
 begin 
  if (hardreset) 
  unused_reset_reg = 4'hF; 
  else unused_reset_reg = next_reset_reg; 
 end 
 always @* 
 begin 
  next_reset_reg = {unused_reset_reg,1'b0}; 
 end 
 endmodule
